190→/// Generate the main.rs harness that calls the target function.
191→///
192→/// Wraps instrumented source in `mod user_code` to avoid name collisions
193→/// (e.g. duplicate `fn main()` when the source file has its own `main`).
194→fn generate_harness(
195→    instrumented_source: &str,
196→    function_name: &str,
197→    param_names: &[String],
198→    param_types: &[String],
199→    return_type: Option<&str>,
200→    inputs_json: &str,
201→    mocks_json: &str,
202→) -> Result<String, ExecuteError> {
203→    let module_block = wrap_in_module(instrumented_source)?;
204→    let mut h = String::with_capacity(4096);
205→
206→    h.push_str("use serde_json::Value;\n\n");
207→    h.push_str(&module_block);
208→    h.push_str("\n\nfn main() {\n");
209→
210→    // Parse inputs
211→    h.push_str(&format!(
212→        "    let inputs_json = r#\"{}\"#;\n",
213→        inputs_json
214→    ));
215→    h.push_str(
216→        "    let inputs: Vec<Value> = serde_json::from_str(inputs_json).unwrap_or_default();\n\n",
217→    );
218→
219→    // Parse and register mocks
220→    h.push_str(&format!(
221→        "    let mocks_json = r#\"{}\"#;\n",
222→        mocks_json
223→    ));
224→    h.push_str("    let mocks: Vec<Value> = serde_json::from_str(mocks_json).unwrap_or_default();\n");
225→    h.push_str("    for mock in &mocks {\n");
226→    h.push_str("        if let (Some(symbol), Some(return_values)) = (\n");
227→    h.push_str("            mock.get(\"symbol\").and_then(|s| s.as_str()),\n");
228→    h.push_str("            mock.get(\"return_values\").and_then(|v| v.as_array()),\n");
229→    h.push_str("        ) {\n");
230→    h.push_str(
231→        "            shatter_rust_runtime::register_mock(symbol, return_values.clone());\n",
232→    );
233→    h.push_str("        }\n");
234→    h.push_str("    }\n\n");
235→
236→    // Reset runtime state
237→    h.push_str("    shatter_rust_runtime::reset();\n\n");
238→
239→    // Deserialize each input parameter
240→    for (i, (name, ty)) in param_names.iter().zip(param_types.iter()).enumerate() {
241→        let clean_name = name.strip_prefix("mut ").unwrap_or(name).trim();
242→        h.push_str(&format!(
243→            "    let {clean_name}: {ty} = serde_json::from_value(inputs[{i}].clone()).unwrap_or_default();\n"
244→        ));
245→    }
246→    h.push('\n');
247→
248→    // Build the argument list
249→    let arg_list: Vec<&str> = param_names
250→        .iter()
251→        .map(|n| n.strip_prefix("mut ").unwrap_or(n).trim())
252→        .collect();
253→    let args = arg_list.join(", ");
254→
255→    // Call the function inside catch_unwind, measuring time
256→    h.push_str("    let start = std::time::Instant::now();\n");
257→    h.push_str("    let result = std::panic::catch_unwind(std::panic::AssertUnwindSafe(|| {\n");
258→    h.push_str(&format!("        user_code::{function_name}({args})\n"));
259→    h.push_str("    }));\n");
260→    h.push_str("    let wall_time_ms = start.elapsed().as_secs_f64() * 1000.0;\n\n");
261→
262→    // Flush runtime results
263→    h.push_str(
264→        "    let runtime_json = shatter_rust_runtime::flush_results();\n",
265→    );
266→    h.push_str(
267→        "    let mut exec_result: Value = serde_json::from_str(&runtime_json).unwrap_or(Value::Object(Default::default()));\n",
268→    );
269→    h.push_str("    let obj = exec_result.as_object_mut().unwrap();\n\n");
270→
271→    // Set return_value or thrown_error
272→    h.push_str("    match result {\n");
273→    if return_type.is_some() {
274→        h.push_str("        Ok(ret_val) => {\n");
275→        h.push_str(
276→            "            obj.insert(\"return_value\".into(), serde_json::to_value(&ret_val).unwrap_or(Value::Null));\n",
277→        );
278→        h.push_str("        }\n");
279→    } else {
280→        h.push_str("        Ok(()) => {\n");
281→        h.push_str("            obj.insert(\"return_value\".into(), Value::Null);\n");
282→        h.push_str("        }\n");
283→    }
284→    h.push_str("        Err(panic_info) => {\n");
285→    h.push_str("            let msg = if let Some(s) = panic_info.downcast_ref::<&str>() {\n");
286→    h.push_str("                s.to_string()\n");
287→    h.push_str("            } else if let Some(s) = panic_info.downcast_ref::<String>() {\n");
288→    h.push_str("                s.clone()\n");
289→    h.push_str("            } else {\n");
290→    h.push_str("                format!(\"{:?}\", panic_info)\n");
291→    h.push_str("            };\n");
292→    h.push_str("            obj.insert(\"thrown_error\".into(), serde_json::json!({\n");
293→    h.push_str("                \"error_type\": \"runtime_error\",\n");
294→    h.push_str("                \"message\": msg,\n");
295→    h.push_str("            }));\n");
296→    h.push_str("        }\n");
297→    h.push_str("    }\n\n");
298→
299→    // Set performance metrics
300→    h.push_str("    obj.insert(\"performance\".into(), serde_json::json!({\n");
301→    h.push_str("        \"wall_time_ms\": wall_time_ms,\n");
302→    h.push_str("        \"cpu_time_us\": 0,\n");
303→    h.push_str("        \"heap_used_bytes\": 0,\n");
304→    h.push_str("        \"heap_allocated_bytes\": 0,\n");
305→    h.push_str("    }));\n\n");
306→
307→    // Ensure side_effects is present
308→    h.push_str("    obj.entry(\"side_effects\").or_insert(serde_json::json!([]));\n\n");
309→
310→    // Print the result JSON to stdout
311→    h.push_str("    println!(\"{}\", serde_json::to_string(&exec_result).unwrap());\n");
312→    h.push_str("}\n");
313→
314→    Ok(h)
315→}
