/// Returns true if `ty` (from syn token stream) is a reference type that
/// needs an owned intermediate for deserialization (e.g. `& str`, `& 'static str`).
fn needs_borrow(ty: &str) -> bool {
    is_str_ref(ty)
}

/// Returns true if `ty` is a reference to `str` (with any lifetime).
fn is_str_ref(ty: &str) -> bool {
    let trimmed = ty.trim();
    if let Some(rest) = trimmed.strip_prefix('&') {
        // After '&', skip optional lifetime ('a, 'static, etc.) then check for `str`
        let rest = rest.trim();
        let rest = if rest.starts_with('\'') {
            // Skip the lifetime token
            rest.split_whitespace().skip(1).collect::<Vec<_>>().join(" ")
        } else {
            rest.to_string()
        };
        rest.trim() == "str"
    } else {
        false
    }
}

/// Maps a param type to an owned type suitable for `serde_json::from_value`.
/// `& str` and `& 'static str` become `String`; everything else passes through.
fn owned_type_for(ty: &str) -> String {
    if is_str_ref(ty) {
        "String".to_string()
    } else {
        ty.to_string()
    }
}

